#!/usr/bin/env node

/**
 * GSD-QDRANT MCP Server
 * 
 * Provides MCP tools for cross-project knowledge retrieval and management.
 * This server connects to Qdrant and exposes tools for searching and retrieving
 * relevant context from the unified GSD knowledge base.
 */

const { McpServer } = require('@modelcontextprotocol/sdk/server/mcp.js');
const { StdioServerTransport } = require('@modelcontextprotocol/sdk/server/stdio.js');
const { z } = require('zod');
const { QdrantClient } = require('@qdrant/js-client-rest');
const path = require('path');
const fs = require('fs');

// Load re-ranking utilities (estimateTokens, trimResultsByTokenBudget)
const { estimateTokens, trimResultsByTokenBudget } = require(path.join(__dirname, '..', 're-ranking'));

// Load query cache for deduplicating repeated queries
const { cache: queryCache } = require(path.join(__dirname, '..', 'query-cache'));

// Read version from this package's package.json (single source of truth)
const MCP_PKG_PATH = path.join(__dirname, 'package.json');
const SERVER_VERSION = (() => {
  try {
    return JSON.parse(fs.readFileSync(MCP_PKG_PATH, 'utf8')).version || '0.0.0';
  } catch (_) {
    return '0.0.0';
  }
})();

// Read environment variables
const QDRANT_URL = process.env.QDRANT_URL || 'http://localhost:6333';
const COLLECTION_NAME = process.env.COLLECTION_NAME || 'gsd_memory';
const VECTOR_NAME = process.env.VECTOR_NAME || 'codebert-768';
const PROJECT_ROOT = process.cwd();

// Load the GSDKnowledgeSync module
// Strategy: try npm module resolution first (works for global/local npm installs),
// then fall back to relative paths (works for local development/symlink).
let GSDKnowledgeSync;

try {
  // 1. Try npm module resolution — works when gsd-qdrant-knowledge is installed as a dependency/peer dep
  const resolved = require.resolve('gsd-qdrant-knowledge');
  GSDKnowledgeSync = require(resolved).GSDKnowledgeSync;
} catch (npmErr) {
  try {
    // 2. Fallback: relative path from source directory
    // When running from source: src/gsd-qdrant-mcp/index.js -> ../../index.js (project root)
    const fallbackPath = path.resolve(__dirname, '..', '..');
    const indexFile = path.join(fallbackPath, 'index.js');
    if (fs.existsSync(indexFile)) {
      GSDKnowledgeSync = require(indexFile).GSDKnowledgeSync;
    } else {
      throw new Error('gsd-qdrant-knowledge not found via npm resolution or relative path');
    }
  } catch (fallbackErr) {
    console.error(
      'Failed to load GSDKnowledgeSync.\n' +
      'Install the main package: npm install -g gsd-qdrant-knowledge\n' +
      'Error:', fallbackErr.message
    );
    process.exit(1);
  }
}

/**
 * Create the MCP server instance
 */
function createMcpServer() {
  const server = new McpServer({
    name: 'gsd-qdrant-knowledge',
    version: SERVER_VERSION,
  });

  // Tool: auto_retrieve - Automatically retrieve relevant context for a task
  server.tool(
    'auto_retrieve',
    'Automatically retrieve relevant cross-project context for the given task using semantic search.',
    {
      task: z.string().describe('The task or query to find relevant context for'),
      limit: z.number().optional().default(3).describe('Maximum number of results to return'),
      maxQueries: z.number().optional().default(2).describe('Maximum number of queries to attempt'),
      includeContent: z.boolean().optional().default(false).describe('Whether to include full content in results'),
    },
    async ({ task, limit = 3, maxQueries = 2, includeContent = false }) => {
      try {
        // Build cache key from normalized query + limit (limit affects result set)
        const cacheKey = `${task}|${limit}`;

        // Check cache first — serve repeated queries without hitting Qdrant
        const cachedResult = queryCache.get(cacheKey);
        if (cachedResult !== undefined) {
          console.log(`[cache] hit: ${cacheKey} → serving from cache`);
          return { content: [{ type: 'text', text: JSON.stringify(cachedResult) }] };
        }

        // Initialize Knowledge Sync
        const sync = new GSDKnowledgeSync();
        await sync.init();

        // Generate query embedding and search using prefetch
        const t0 = Date.now();
        const vector = await sync.embedText(task);

        // Detect search intent and build Qdrant filter from certain filters (must)
        // vs uncertain ones (should). This ensures language/type/project constraints
        // are applied as hard must-clauses when the intent is confident.
        const { detectIntent, buildQdrantFilter } = require(path.join(__dirname, '..', 'intent-detector'));
        const intent = detectIntent(task);
        const qdrantFilter = buildQdrantFilter(intent);

        // Grouped search: return max GROUP_SIZE chunks per source document.
        const GROUP_SIZE = 2;        // max chunks per source document
        const LIMIT = 5;             // max results to return
        const SCORE_THRESHOLD = 0.85;  // minimum score for inclusion
        const FALLBACK_THRESHOLD = 0.75; // lowered threshold if too few results

        let hits = [];
        let groupCount = 0;
        try {
          const groupConfig = {
            vector: { name: VECTOR_NAME, vector },
            group_by: 'source',
            group_size: GROUP_SIZE,
            limit: LIMIT * 3,  // request more groups so we can filter by threshold after
            score_threshold: SCORE_THRESHOLD,
            with_payload: true,
            with_vector: false,
          };
          if (qdrantFilter) {
            groupConfig.filter = qdrantFilter;
          }
          const groupedResults = await sync.client.searchPointGroups(COLLECTION_NAME, groupConfig);
          groupCount = groupedResults.groups.length;

          // Flatten groups into a single hits array
          for (const group of groupedResults.groups) {
            hits = hits.concat(group.hits);
          }
        } catch (groupErr) {
          // Fallback: plain search with client-side dedup
          console.warn('[qdrant] searchPointGroups failed, falling back to search');
          try {
            const searchConfig = {
              vector: { name: VECTOR_NAME, vector },
              limit: LIMIT * 10,
              score_threshold: SCORE_THRESHOLD,
              with_payload: true,
              with_vector: false,
            };
            if (qdrantFilter) {
              searchConfig.filter = qdrantFilter;
            }
            const rawHits = await sync.client.search(COLLECTION_NAME, searchConfig);

            // Client-side dedup: max GROUP_SIZE per source document
            const sourceCounts = {};
            for (const hit of rawHits) {
              const src = hit.payload && hit.payload.source;
              if (!src || (sourceCounts[src] || 0) >= GROUP_SIZE) continue;
              sourceCounts[src] = (sourceCounts[src] || 0) + 1;
              hits.push(hit);
            }
            groupCount = Object.keys(sourceCounts).length;
          } catch (searchErr) {
            console.warn('[qdrant] search also failed, returning empty:', searchErr.message);
          }
        }

        // Log totals before threshold filtering
        const totalResults = hits.length;
        console.log('[qdrant] auto_retrieve: results: %d total, %d above threshold', totalResults, hits.filter(h => h.score >= SCORE_THRESHOLD).length);

        // Apply score threshold filter
        let rankedHits = hits.filter(hit => hit.score >= SCORE_THRESHOLD);

        // Fallback: if fewer than 2 results above threshold, retry with lowered threshold
        if (rankedHits.length < 2 && totalResults > 0) {
           console.log(`[qdrant] auto_retrieve: fallback: only ${rankedHits.length} results above ${SCORE_THRESHOLD.toFixed(2)}, retrying with ${FALLBACK_THRESHOLD.toFixed(2)}`);
          rankedHits = hits.filter(hit => hit.score >= FALLBACK_THRESHOLD);
        }

        // Sort by Qdrant score descending
        const sortedByQdrantScore = rankedHits.sort((a, b) => b.score - a.score);

        const elapsed = Date.now() - t0;
        console.log(`[qdrant] auto_retrieve: groups=${groupCount}, chunks=${totalResults} (threshold=${SCORE_THRESHOLD.toFixed(2)} → ${rankedHits.length} above), in ${elapsed}ms`);

        const projectId = PROJECT_ROOT.split(/[/\\]/).pop();

        // Rank results prioritizing cross-project reuse without excluding current project results.
        // Use threshold-filtered hits (sortedByQdrantScore) instead of raw hits.
        const ranked = sortedByQdrantScore.map(hit => {
          const recencyScore = Math.min(1, (Date.now() - hit.payload.timestamp) / (30 * 24 * 60 * 60 * 1000));
          const importanceScore = (hit.payload.importance || 1) / 5;
          const reusableBoost = hit.payload.reusable ? 0.08 : 0;
          const crossProjectBoost = hit.payload.project_id && hit.payload.project_id !== projectId ? 0.12 : 0;
          const sameProjectBoost = hit.payload.project_id === projectId ? 0.04 : 0;
          const score = hit.score * 0.6 + (1 - recencyScore) * 0.15 + importanceScore * 0.05 + reusableBoost + crossProjectBoost + sameProjectBoost;
          return { ...hit.payload, score };
        }).slice(0, limit);

        // Token estimation: calculate total tokens across all result text fields
        let totalTokens = 0;
        for (const r of ranked) {
          if (!r) continue;
          const textFields = [r.content, r.summary, r.text].filter(Boolean);
          for (const field of textFields) {
            totalTokens += estimateTokens(field);
          }
        }

        // Trim results if over token budget (4000 tokens default)
        let trimmedInfo;
        try {
          trimmedInfo = trimResultsByTokenBudget(ranked, { maxTokens: 4000 });
        } catch (_) { /* non-fatal — proceed with untrimmed */ }

        // Clean up internal _truncated flag before output
        for (const r of ranked) {
          if (r && '_truncated' in r) delete r._truncated;
        }

        console.log(`[retrieval] ${ranked.length} results, ~${totalTokens} estimated tokens` +
          (trimmedInfo && trimmedInfo.trimmed ? `, trimmed to 500 chars per result` : ''));

        // Format results for MCP response
        const results = ranked.map(hit => ({
          type: hit.type,
          subtype: hit.subtype,
          project_id: hit.project_id,
          source: hit.source,
          summary: hit.summary,
          content: includeContent ? hit.content : null,
          tags: hit.tags,
          language: hit.language,
          reusable: hit.reusable,
          importance: hit.importance,
          relevance_score: hit.score,
          match_type: 'semantic',
        }));

        const cachePayload = {
          task,
          results,
          totalResults: ranked.length,
          projectId,
        };

        // Store in cache for future repeated queries
        queryCache.set(cacheKey, cachePayload);
        console.log(`[cache] stored: ${cacheKey} (${ranked.length} results)`);

        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify(cachePayload),
            },
          ],
        };
      } catch (err) {
        console.error('auto_retrieve error:', err);
        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                error: err.message,
                results: [],
              }),
            },
          ],
        };
      }
    },
  );

  // Tool: list_projects - List all projects in the knowledge base
  server.tool(
    'list_projects',
    'List all unique project IDs that have been indexed in the knowledge base.',
    {},
    async () => {
      try {
        const sync = new GSDKnowledgeSync();
        await sync.init();

        // Get all documents from the collection
        const scrollResult = await sync.client.scroll(COLLECTION_NAME, {
          limit: 1000,
          with_payload: ['project_id'],
        });

        // Extract unique project IDs (scroll returns 'points', not 'hits')
        const projects = new Set();
        for (const point of scrollResult.points) {
          if (point.payload && point.payload.project_id) {
            projects.add(point.payload.project_id);
          }
        }

        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                projects: Array.from(projects),
                totalProjects: projects.size,
              }),
            },
          ],
        };
      } catch (err) {
        console.error('list_projects error:', err);
        return {
          content: [
            {
              type: 'text',
              text: JSON.stringify({
                error: err.message,
                projects: [],
                totalProjects: 0,
              }),
            },
          ],
        };
      }
    },
  );

  return server;
}

// Start the server
const server = createMcpServer();
const transport = new StdioServerTransport();
server.connect(transport).catch((err) => {
  console.error('Failed to connect server:', err);
  process.exit(1);
});

/**
 * QueryCache — in-memory LRU cache with TTL for Qdrant query results.
 *
 * Features:
 *  - Map-backed storage with per-entry timestamps (TTL-based expiry)
 *  - Background sweep interval removes expired entries every 60 seconds
 *  - Max size of 100 entries; oldest entry evicted on overflow (LRU-ish)
 *  - Stats tracking: hits, misses for logging
 */

const TTL_MS = 5 * 60 * 1000; // 5 minutes
const MAX_SIZE = 100;
const SWEEP_INTERVAL_MS = 60 * 1000; // sweep every 60 seconds

let hits = 0;
let misses = 0;

// Stopwords — English + Italian (union set for deduplication)
const STOPWORDS_EN = new Set([
  'a', 'an', 'the', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
  'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could',
  'should', 'may', 'might', 'shall', 'can', 'need', 'dare', 'ought',
  'used', 'to', 'of', 'in', 'for', 'on', 'with', 'at', 'by', 'from',
  'as', 'into', 'through', 'during', 'before', 'after', 'above', 'below',
  'between', 'out', 'off', 'over', 'under', 'again', 'further', 'then',
  'once', 'here', 'there', 'when', 'where', 'why', 'how', 'all', 'both',
  'each', 'few', 'more', 'most', 'other', 'some', 'such', 'no', 'nor',
  'not', 'only', 'own', 'same', 'so', 'than', 'too', 'very', 'just',
  'because', 'but', 'and', 'or', 'if', 'while', 'about', 'up', 'any'
]);

const STOPWORDS_IT = new Set([
  // Articoli
  'il', 'lo', 'la', 'i', 'gli', 'le', 'un', 'uno', 'una', "un'",
  // Preposizioni articolate
  'del', 'dello', 'della', 'dei', 'degli', 'delle',
  'nel', 'nello', 'nella', 'nei', 'negli', 'nelle',
  'sul', 'sullo', 'sulla', 'sui', 'sugli', 'sulle',
  // Preposizioni articolate con "da" (dal, dallo...) e forme contratte
  'col', 'colla', 'coi', 'cogli', 'cole',
  'al', 'allo', 'alla', 'ai', 'agli', 'alle',
  // Preposizioni semplici
  'di', 'da', 'in', 'con', 'su', 'per', 'tra', 'fra',
  // Pronomi
  'mi', 'ti', 'ci', 'vi', 'si', 'lo', 'la', 'li', 'le', 'ne', 'gli',
  // Congiunzioni e altre
  'che', 'e', 'ed', 'o', 'oppure', 'ma', 'perché', 'poiché', 'siccome',
  'se', 'quando', 'mentre', 'dopo', 'prima', 'subito', 'appena',
  'così', 'anche', 'non', 'più', 'meno', 'troppo', 'abbastanza',
  'qui', 'quà', 'qua', 'lì', 'là', 'come', 'dove', 'dunque',
  'pertanto', 'infatti', 'cioè', 'vale', 'a dire'
]);

const STOPWORDS = new Set([...STOPWORDS_EN, ...STOPWORDS_IT]);

/**
 * Normalize a query string for cache key generation.
 * Steps: lowercase → split on whitespace/punctuation → filter stopwords → join.
 * @param {string} query - Original user query
 * @returns {string} Normalized query suitable as a cache key
 */
function normalizeQuery(query) {
  if (typeof query !== 'string' || !query.trim()) return '';

  const normalized = query.toLowerCase().trim();
  const tokens = normalized.split(/[\s\-_]+/);
  const filtered = tokens.filter(t => t.length > 0 && !STOPWORDS.has(t));
  const result = filtered.join(' ');

  console.log('[cache] normalized: %s → %s', query, result);
  return result;
}

class QueryCache {
  constructor() {
    this.store = new Map(); // key → { value, timestamp }
    this._sweepTimer = null;
    this.startSweep();
  }

  /** Start background sweep of expired entries */
  startSweep() {
    if (this._sweepTimer) return;
    this._sweepTimer = setInterval(() => this.sweep(), SWEEP_INTERVAL_MS);
    // Make the timer non-blocking so it doesn't prevent process exit
    if (this._sweepTimer.unref) this._sweepTimer.unref();
  }

  /** Remove all expired entries from the store */
  sweep() {
    const now = Date.now();
    let removed = 0;
    for (const [key, entry] of this.store.entries()) {
      if (now - entry.timestamp > TTL_MS) {
        this.store.delete(key);
        removed++;
      }
    }
    if (removed > 0) {
      console.log(`[cache] sweep: removed ${removed} expired entries, remaining=${this.store.size}`);
    }
  }

  /** Get a cached value by key. Normalizes the key first for fuzzy matching. Returns undefined on miss or expiry. */
  get(key) {
    const normalized = normalizeQuery(key);
    if (!normalized) return undefined;

    const entry = this.store.get(normalized);
    if (!entry) {
      misses++;
      return undefined;
    }
    // Check TTL
    if (Date.now() - entry.timestamp > TTL_MS) {
      this.store.delete(normalized);
      misses++;
      console.log(`[cache] expired: ${normalized}`);
      return undefined;
    }
    hits++;
    return entry.value;
  }

  /** Set a value in the cache with current timestamp. Normalizes the key first. Evicts oldest if at capacity. */
  set(key, value) {
    const normalized = normalizeQuery(key);
    if (!normalized) return;

    // If key already exists, update it in place (move to "recently used")
    if (this.store.has(normalized)) {
      this.store.set(normalized, { value, timestamp: Date.now() });
      return;
    }

    // Evict oldest entry if at capacity
    if (this.store.size >= MAX_SIZE) {
      const oldestKey = this.store.keys().next().value;
      this.store.delete(oldestKey);
      console.log(`[cache] evicted: ${oldestKey} (max size=${MAX_SIZE})`);
    }

    this.store.set(normalized, { value, timestamp: Date.now() });
  }

  /** Check if a key exists without updating its TTL. Normalizes the key first. */
  has(key) {
    const normalized = normalizeQuery(key);
    if (!normalized) return false;

    const entry = this.store.get(normalized);
    if (!entry) return false;
    // Still respect expiry even for has()
    if (Date.now() - entry.timestamp > TTL_MS) {
      this.store.delete(normalized);
      return false;
    }
    return true;
  }

  /** Clear all entries from the cache. */
  clear() {
    const size = this.store.size;
    this.store.clear();
    console.log(`[cache] cleared: ${size} entries removed`);
  }

  /** Get current stats (hits, misses, size). */
  getStats() {
    return { hits, misses, size: this.store.size };
  }

  /** Reset all counters. Useful for testing. */
  resetStats() {
    hits = 0;
    misses = 0;
  }

  /** Stop the background sweep timer. */
  stopSweep() {
    if (this._sweepTimer) {
      clearInterval(this._sweepTimer);
      this._sweepTimer = null;
    }
  }
}

// Singleton instance — shared across all imports
const cache = new QueryCache();

module.exports = { cache, normalizeQuery };

/**
 * Re-ranking Module
 * 
 * Applies recency boost and path matching to Qdrant search results.
 * Results with recent lastModified timestamps get a +0.05 score boost,
 * and results whose source paths contain query words get an additional +0.15 boost.
 */

/**
 * Apply recency boost and path matching to ranked results.
 * 
 * @param {Array} results - Array of result objects with at least: score (number), source (string)
 *   Results may include lastModified (unix timestamp in seconds).
 *   For path matching, either pass `query` as the second param or attach `_query` on each result.
 * @param {Object|number|string} [optionsOrDays] - Either a number of days (default 30) or an options object
 * @param {string} [rawQuery] - Optional raw query string for path matching (legacy: use options.query instead)
 * @returns {Array} The same results array with updated scores (mutated in place)
 */
function applyRecencyBoost(results, optionsOrDays = 30, rawQuery) {
  let days;
  let enablePathMatch = true;

  if (typeof optionsOrDays === 'object') {
    days = typeof optionsOrDays.days === 'number' ? optionsOrDays.days : 30;
    enablePathMatch = optionsOrDays.pathMatch !== false;
  } else {
    days = Number(optionsOrDays) || 30;
  }

  if (!results || results.length === 0) return results;

  // Determine the raw query: from explicit param, or _query on first result
  const query = (rawQuery && rawQuery.trim()) 
    ? rawQuery.trim() 
    : (results[0] && typeof results[0]._query === 'string' ? results[0]._query : '');

  const now = Date.now();
  const recentCutoffMs = now - days * 86400000;

  let totalBoost = 0;
  let boostedCount = 0;

  for (const result of results) {
    if (!result || typeof result.score !== 'number') continue;

    let boost = 0;

    // Recency boost: +0.05 if lastModified is within the configured window
    const lastMod = result.lastModified ? parseInt(result.lastModified, 10) : null;
    if (lastMod && lastMod * 1000 > recentCutoffMs) {
      boost += 0.05;
      boostedCount++;
    }

    // Path matching: +0.15 if query words appear in the source path
    if (enablePathMatch && result.source && query.length >= 3) {
      const lowerSource = String(result.source).toLowerCase();
      const words = query.split(/\s+/).filter(w => w.length >= 3);

      for (const word of words) {
        if (lowerSource.includes(word)) {
          boost += 0.15;
          break; // Only one path match bonus per result, even if multiple query words match
        }
      }
    }

    totalBoost += boost;
    result.score = Math.min(1.0, result.score + boost);
  }

  const avgBoost = results.length > 0 ? totalBoost / results.length : 0;
  console.log(`[rerank] ${results.length} results scored, avg boost: ${avgBoost.toFixed(3)}`);

  return results;
}

/**
 * Estimate the number of tokens in a text string.
 * Uses ~4 characters per token — a conservative approximation suitable for code/text mix.
 * @param {string} text - Text to estimate tokens for
 * @returns {number} Estimated token count (integer)
 */
function estimateTokens(text) {
  if (!text || typeof text !== 'string') return 0;
  return Math.ceil(text.length / 4);
}

/**
 * Trim results when total estimated tokens exceed a limit.
 * Keeps top-K results and truncates each result's content to first `maxChars` chars.
 * Mutates the input array in place (adds trimmed flag, truncates text fields).
 * @param {Array} results - Array of result objects with at least: score (number), content? (string)
 * @param {Object} options
 * @param {number} [options.maxTokens=4000] - Maximum total estimated tokens allowed
 * @param {number} [options.maxCharsPerResult=500] - Max chars to keep per truncated result
 * @returns {{ trimmed: boolean, originalCount: number, finalCount: number }} Info about trimming performed
 */
function trimResultsByTokenBudget(results, options = {}) {
  const maxTokens = typeof options.maxTokens === 'number' ? options.maxTokens : 4000;
  const maxCharsPerResult = typeof options.maxCharsPerResult === 'number' ? options.maxCharsPerResult : 500;

  if (!results || results.length === 0) {
    return { trimmed: false, originalCount: 0, finalCount: 0 };
  }

  // Calculate total estimated tokens from content + summary fields
  let totalTokens = 0;
  for (const r of results) {
    if (!r) continue;
    const textFields = [r.content, r.summary, r.text].filter(Boolean);
    for (const field of textFields) {
      totalTokens += estimateTokens(field);
    }
  }

  // No trimming needed — stay under budget
  if (totalTokens <= maxTokens) {
    return { trimmed: false, originalCount: results.length, finalCount: results.length };
  }

  const originalCount = results.length;

  // Truncate content/summary fields to maxCharsPerResult and mark as truncated
  for (const r of results) {
    if (!r) continue;
    if (r.content && r.content.length > maxCharsPerResult) {
      r.content = r.content.slice(0, maxCharsPerResult);
      r._truncated = true;
    }
    // Also truncate text field if present and larger than limit
    if (r.text && r.text.length > maxCharsPerResult) {
      r.text = r.text.slice(0, maxCharsPerResult);
      r._truncated = true;
    }
  }

  return { trimmed: true, originalCount, finalCount: results.length };
}

module.exports = { applyRecencyBoost, estimateTokens, trimResultsByTokenBudget };

#!/usr/bin/env node

/**
 * GSD + Qdrant CLI - Main entry point
 */

const { spawnSync } = require('child_process');
const http = require('http');
const fs = require('fs');
const { existsSync, readFileSync, mkdirSync, writeFileSync, copyFileSync, rmSync, unlinkSync } = fs;
const { join, dirname, extname, basename } = require('path');
const readline = require('readline');
const { applyRecencyBoost, estimateTokens, trimResultsByTokenBudget } = require('./re-ranking');

const PROJECT_ROOT = process.cwd();
const ROOT_PKG = join(PROJECT_ROOT, 'package.json');
const API_PKG = join(PROJECT_ROOT, 'apps', 'api', 'package.json');
const CLI_ROOT = __dirname;
const TOOL_DIR_NAME = 'gsd-qdrant-knowledge';
const TOOL_DIR = join(PROJECT_ROOT, TOOL_DIR_NAME);
const TOOL_MCP_FILE = join(TOOL_DIR, 'mcp.json');
const ROOT_MCP_FILE = join(PROJECT_ROOT, '.mcp.json');
const TOOL_MARKER = 'managedBy';
const TOOL_MARKER_VALUE = 'gsd-qdrant-knowledge';
const MCP_SERVER_NAME = 'gsd-qdrant';

const DEFAULT_QDRANT_URL = 'http://localhost:6333';
const QDRANT_HEALTHZ_PATH = '/healthz';

/**
 * Resolve the actual path to gsd-qdrant-mcp/index.js.
 * Tries: local node_modules → global npm root → relative (dev symlink).
 * Returns null if nothing is found.
 */
function getMcpServerPath() {
  // 1. Local resolution
  try {
    const resolved = require.resolve('gsd-qdrant-knowledge');
    const mcpPath = join(dirname(resolved), 'src', 'gsd-qdrant-mcp', 'index.js');
    if (existsSync(mcpPath)) return mcpPath;
  } catch (_) {}

  // 2. Global npm root resolution
  try {
    const globalModules = getGlobalNodeModulesPath();
    if (globalModules) {
      const mcpPath = join(globalModules, 'gsd-qdrant-knowledge', 'src', 'gsd-qdrant-mcp', 'index.js');
      if (existsSync(mcpPath)) return mcpPath;
    }
  } catch (_) {}

  // 3. Relative path from CLI root (development / symlink)
  const cliRoot = __dirname;
  const candidates = [
    join(cliRoot, 'gsd-qdrant-mcp', 'index.js'),
    join(dirname(cliRoot), 'src', 'gsd-qdrant-mcp', 'index.js'),
  ];
  for (const p of candidates) {
    if (existsSync(p)) return p;
  }

  return null;
}

function findFileInCliRoot(filename) {
  const pathInCliRoot = join(CLI_ROOT, filename);
  if (existsSync(pathInCliRoot)) return pathInCliRoot;
  return join(dirname(CLI_ROOT), filename);
}

function getExtensionForLanguage(language) {
  if (!language) return '.js';
  const lang = language.toLowerCase();
  const extensions = {
    javascript: '.js', js: '.js', typescript: '.ts', ts: '.ts', python: '.py', py: '.py',
    go: '.go', rust: '.rs', java: '.java', c: '.c', cpp: '.cpp', 'c++': '.cpp', 'c#': '.cs',
    ruby: '.rb', php: '.php', swift: '.swift', kt: '.kt', kotlin: '.kt', scala: '.scala',
    html: '.html', css: '.css', scss: '.scss', less: '.less', json: '.json', yaml: '.yaml',
    yml: '.yml', markdown: '.md', md: '.md', sql: '.sql', sh: '.sh', bash: '.sh', zsh: '.zsh',
    powershell: '.ps1', r: '.r', rscript: '.r'
  };
  return extensions[lang] || '.js';
}

function run(command, args, options = {}) {
  return spawnSync(command, args, {
    stdio: 'inherit',
    shell: true,
    env: process.env,
    ...options,
  });
}

const REQUIRED_PACKAGES = [
  '@qdrant/js-client-rest',
  '@xenova/transformers',
  '@modelcontextprotocol/sdk',
  'zod'
];

function findPackagePath() {
  if (existsSync(API_PKG)) return API_PKG;
  if (existsSync(ROOT_PKG)) return ROOT_PKG;
  return null;
}

function getGlobalNodeModulesPath() {
  try {
    const result = spawnSync('npm', ['root', '-g'], { shell: true });
    if (result.status === 0) return result.stdout.toString().trim();
  } catch (_) {}
  return null;
}

function areRequiredPackagesInstalled(projectRoot, pkgPath) {
  try {
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
    const declaredDeps = { ...(pkg.dependencies || {}), ...(pkg.devDependencies || {}) };

    for (const dep of REQUIRED_PACKAGES) {
      if (!declaredDeps[dep]) continue;
      try {
        require.resolve(dep, { paths: [projectRoot] });
        continue;
      } catch (_) {
        const globalPath = getGlobalNodeModulesPath();
        if (globalPath) {
          try {
            require.resolve(dep, { paths: [globalPath] });
            continue;
          } catch (_) {}
        }
        return false;
      }
    }

    return true;
  } catch (_) {
    return false;
  }
}

function installDependencies(pkgPath) {
  if (areRequiredPackagesInstalled(PROJECT_ROOT, pkgPath)) {
    console.log('📦 Dependencies: ok');
    return 'ok';
  }

  console.log('📦 Dependencies: installing missing packages...');
  const result = run('npm', ['install', ...REQUIRED_PACKAGES], { cwd: PROJECT_ROOT });
  if (result.status !== 0) {
    console.error('❌ Dependency installation failed.');
    process.exit(result.status || 1);
  }
  return 'installed';
}

function readJsonFile(path, fallback) {
  try {
    return JSON.parse(readFileSync(path, 'utf8'));
  } catch (_) {
    return fallback;
  }
}

function writeJsonFile(path, value) {
  writeFileSync(path, JSON.stringify(value, null, 2) + '\n', 'utf8');
}

// ─── QDrant health check ──────────────────────────────────────────────

/**
 * Check if a QDrant server is healthy at the given URL.
 * Qdrant v1.x returns plain text "healthz check passed" on /healthz.
 * Returns true if the response indicates health.
 * @param {string} url - Base URL (e.g. http://localhost:6333)
 * @returns {Promise<boolean>}
 */
async function checkQdrantHealth(url) {
  return new Promise((resolve) => {
    const req = http.get(`${url}${QDRANT_HEALTHZ_PATH}`, (res) => {
      let body = '';
      res.on('data', (chunk) => { body += chunk; });
      res.on('end', () => {
        // Qdrant v1.x returns plain text "healthz check passed"
        const ok = body.includes('ok') || body.includes('passed');
        resolve(ok);
      });
    });
    req.on('error', () => { resolve(false); });
    req.setTimeout(3000, () => { req.destroy(); resolve(false); });
  });
}

/**
 * Check if QDrant is running. Exits with error if not available.
 * @returns {{ url: string }}
 */
async function ensureQdrantRunning() {
  const qdrantUrl = process.env.QDRANT_URL || DEFAULT_QDRANT_URL;

  const healthy = await checkQdrantHealth(qdrantUrl);
  if (healthy) {
    console.log('✅ QDrant server detected at ' + qdrantUrl);
    return { url: qdrantUrl };
  }

  console.error('❌ QDrant is not running at ' + qdrantUrl);
  console.error('   Start it with: docker run -d --name qdrant -p 6333:6333 qdrant/qdrant');
  console.error('   Or set QDRANT_URL environment variable to your QDrant instance.');
  process.exit(1);
}

function createGsdQdrantDirectory(projectRoot) {
  const stateFile = join(TOOL_DIR, '.qdrant-sync-state.json');
  const packageFile = join(TOOL_DIR, 'package.json');
  const indexFile = join(TOOL_DIR, 'index.js');

  if (!existsSync(TOOL_DIR)) {
    mkdirSync(TOOL_DIR, { recursive: true });
    console.log(`📂 Created directory: ${TOOL_DIR_NAME}/`);
  }

  if (!existsSync(stateFile)) {
    writeJsonFile(stateFile, { lastSync: null, indexed: {} });
    console.log(`📝 Created: ${TOOL_DIR_NAME}/.qdrant-sync-state.json`);
  }

  if (!existsSync(packageFile)) {
    writeFileSync(packageFile, JSON.stringify({ type: 'commonjs' }, null, 2) + '\n', 'utf8');
    console.log(`📝 Created: ${TOOL_DIR_NAME}/package.json`);
  }

  if (!existsSync(indexFile)) {
    const templateIndexFile = findFileInCliRoot('gsd-qdrant-template.js');
    copyFileSync(templateIndexFile, indexFile);
    console.log(`📝 Created: ${TOOL_DIR_NAME}/index.js`);
  }
}

function ensureToolMcpConfig() {
  const mcpPath = getMcpServerPath();
  if (!mcpPath) {
    console.warn('⚠️  Cannot resolve gsd-qdrant-mcp path. Please reinstall the package.');
    return;
  }

  const config = {
    [TOOL_MARKER]: TOOL_MARKER_VALUE,
    serverName: MCP_SERVER_NAME,
    mcpServers: {
      [MCP_SERVER_NAME]: {
        command: 'node',
        args: [mcpPath],
        cwd: '.',
        env: {
          QDRANT_URL: process.env.QDRANT_URL || 'http://localhost:6333',
          COLLECTION_NAME: process.env.COLLECTION_NAME || 'gsd_memory',
          VECTOR_NAME: process.env.VECTOR_NAME || 'codebert-768'
        }
      }
    }
  };
  const existed = existsSync(TOOL_MCP_FILE);
  writeJsonFile(TOOL_MCP_FILE, config);
  console.log(`${existed ? '📝 Updated' : '📝 Created'}: ${TOOL_DIR_NAME}/mcp.json`);
}

function ensureRootMcpRegistration() {
  const mcpPath = getMcpServerPath();
  if (!mcpPath) {
    console.warn('⚠️  Cannot resolve gsd-qdrant-mcp path. Please reinstall the package.');
    return;
  }

  const current = readJsonFile(ROOT_MCP_FILE, { mcpServers: {} });
  const mcpServers = current.mcpServers && typeof current.mcpServers === 'object' ? current.mcpServers : {};
  const desired = {
    command: 'node',
    args: [mcpPath],
    cwd: '.',
    env: {
      QDRANT_URL: process.env.QDRANT_URL || 'http://localhost:6333',
      COLLECTION_NAME: process.env.COLLECTION_NAME || 'gsd_memory',
      VECTOR_NAME: process.env.VECTOR_NAME || 'codebert-768'
    }
  };

  const previous = JSON.stringify(mcpServers[MCP_SERVER_NAME] || null);
  const next = JSON.stringify(desired);
  if (previous === next) {
    console.log('ℹ️  MCP server already registered in .mcp.json');
    return;
  }

  mcpServers[MCP_SERVER_NAME] = desired;
  current.mcpServers = mcpServers;
  writeJsonFile(ROOT_MCP_FILE, current);
  console.log('📝 Updated: .mcp.json');
}

function removeRootMcpRegistration() {
  if (!existsSync(ROOT_MCP_FILE)) return;
  const current = readJsonFile(ROOT_MCP_FILE, null);
  if (!current || !current.mcpServers || !current.mcpServers[MCP_SERVER_NAME]) return;
  delete current.mcpServers[MCP_SERVER_NAME];
  if (Object.keys(current.mcpServers).length === 0) {
    unlinkSync(ROOT_MCP_FILE);
    console.log('🧹 Removed: .mcp.json');
    return;
  }
  writeJsonFile(ROOT_MCP_FILE, current);
  console.log('🧹 Updated: .mcp.json');
}

async function addToGitignore(projectRoot, entry) {
  const gitignorePath = join(projectRoot, '.gitignore');
  if (!existsSync(gitignorePath)) {
    console.log('ℹ️  .gitignore not found, skipping');
    return;
  }
  const content = await fs.promises.readFile(gitignorePath, 'utf8');
  const lines = content.split('\n');
  if (lines.some(line => line.trim() === entry)) {
    console.log('ℹ️  Entry already in .gitignore');
    return;
  }
  await fs.promises.writeFile(gitignorePath, content + '\n' + entry + '\n', 'utf8');
  console.log(`📝 Added '${entry}' to .gitignore`);
}

async function removeFromGitignore(projectRoot, entry) {
  const gitignorePath = join(projectRoot, '.gitignore');
  if (!existsSync(gitignorePath)) return;
  const content = await fs.promises.readFile(gitignorePath, 'utf8');
  const next = content
    .split('\n')
    .filter(line => line.trim() !== entry)
    .join('\n')
    .replace(/\n{3,}/g, '\n\n');
  if (next !== content) {
    await fs.promises.writeFile(gitignorePath, next, 'utf8');
    console.log(`🧹 Removed '${entry}' from .gitignore`);
  }
}

async function uninstallProjectArtifacts() {
  // Step 1: Clean up Qdrant collection FIRST — delete all points for this project
  // Uses server-side filter (scroll ignores unknown params) so only matching points are fetched.
  const qdrantUrl = process.env.QDRANT_URL || DEFAULT_QDRANT_URL;
  try {
    const templatePath = findFileInCliRoot('gsd-qdrant-template.js');
    if (templatePath) {
      const { GSDKnowledgeSync } = require(templatePath);
      // Override QDRANT_URL env for this instance
      const sync = new GSDKnowledgeSync();
      sync.client = new (require('@qdrant/js-client-rest').QdrantClient)({ url: qdrantUrl });
      const deleted = await sync.deleteAllProjectPoints();
      if (deleted > 0) {
        console.log(`🧹 Qdrant: Deleted ${deleted} point(s) for project '${sync.projectName}'`);
      } else {
        console.log(`ℹ️  Qdrant: No points found for project '${sync.projectName}'`);
      }
    }
  } catch (err) {
    console.warn('⚠️  Qdrant cleanup skipped (collection may not exist or be unreachable):', err.message);
  }

  // Step 2: Remove local artifacts
  removeRootMcpRegistration();

  const hooksDir = join(PROJECT_ROOT, '.git', 'hooks');
  if (existsSync(hooksDir)) {
    for (const hook of ['post-commit.sh', 'post-commit.bat']) {
      const hookPath = join(hooksDir, hook);
      if (existsSync(hookPath)) {
        // Verifica che sia il nostro hook prima di rimuovere
        try {
          const content = readFileSync(hookPath, 'utf8');
          if (content.includes('gsd-qdrant-knowledge')) {
            unlinkSync(hookPath);
            console.log(`🧹 Removed: .git/hooks/${hook}`);
          }
        } catch (_) {}
      }
    }
  }

  if (existsSync(TOOL_DIR)) {
    rmSync(TOOL_DIR, { recursive: true, force: true });
    console.log(`🧹 Removed: ${TOOL_DIR_NAME}/`);
  }

 // Remove auto-retrieve instructions from project-level KNOWLEDGE.md
  const instructionsScript = findFileInCliRoot('knowledge-instructions.js');
  if (existsSync(instructionsScript)) {
    try {
      const { removeKnowledgeInstructions } = require(instructionsScript);
      removeKnowledgeInstructions({ cwd: PROJECT_ROOT });
    } catch (err) {
      console.warn('⚠️  Knowledge instructions cleanup failed:', err.message);
    }
  }
}

function installPostCommitHook() {
  const hooksDir = join(PROJECT_ROOT, '.git', 'hooks');
  if (!existsSync(hooksDir)) return;

  const isWindows = process.platform === 'win32';
  const hookName = isWindows ? 'post-commit.bat' : 'post-commit.sh';
  const hookPath = join(hooksDir, hookName);

  // Cerca il template in ordine: src/hooks/ → root/hooks/
  const templates = [
    join(CLI_ROOT, 'hooks', hookName),
    join(dirname(CLI_ROOT), 'src', 'hooks', hookName),
    join(PROJECT_ROOT, 'src', 'hooks', hookName),
  ];

  let hookContent = null;
  for (const t of templates) {
    if (existsSync(t)) {
      hookContent = readFileSync(t, 'utf8');
      break;
    }
  }

  if (!hookContent) return;

  try {
    const existing = readFileSync(hookPath, 'utf8');
    if (existing === hookContent) return;
  } catch (_) {}

  writeFileSync(hookPath, hookContent, { mode: isWindows ? undefined : 0o755 });
  console.log(`📝 Post-commit hook installed (${hookName})`);
}

async function bootstrapProject() {
  console.log('🚀 GSD + Qdrant CLI\n');
  createGsdQdrantDirectory(PROJECT_ROOT);

  // Ensure auto-retrieve instructions are in project-level KNOWLEDGE.md (safe to run multiple times)
  const instructionsScript = findFileInCliRoot('knowledge-instructions.js');
  if (existsSync(instructionsScript)) {
    try {
      const { ensureKnowledgeInstructions } = require(instructionsScript);
      ensureKnowledgeInstructions();
    } catch (err) {
      console.warn('⚠️  Knowledge instructions setup failed:', err.message);
    }
  }

  const installExtensionScript = findFileInCliRoot('install-gsd-extension.js');
  if (existsSync(installExtensionScript)) {
    const installResult = spawnSync('node', [installExtensionScript], {
      cwd: PROJECT_ROOT,
      stdio: 'inherit',
      shell: false
    });
    if (installResult.status !== 0) {
      console.error('⚠️  GSD extension installation failed');
    }
  }

  ensureToolMcpConfig();
  ensureRootMcpRegistration();

  const pkgPath = findPackagePath();
  if (!pkgPath) {
    console.error('❌ No package.json found. Are you in a Node.js project?');
    process.exit(1);
  }

  console.log(`📁 Project: ${basename(PROJECT_ROOT)}`);
  installDependencies(pkgPath);
  run('node', [findFileInCliRoot('setup-from-templates.js')], { cwd: PROJECT_ROOT });

  // Install post-commit hook for automatic knowledge sync
  installPostCommitHook();

  await addToGitignore(PROJECT_ROOT, `${TOOL_DIR_NAME}/`);

  // Ensure QDrant is running before sync
  const qdrantResult = await ensureQdrantRunning();

  // Run sync with the correct QDRANT_URL in env
  const syncScript = findFileInCliRoot('sync-knowledge.js');
  const syncResult = spawnSync('node', [syncScript], {
    cwd: PROJECT_ROOT,
    stdio: 'inherit',
    env: { ...process.env },
  });
  if (syncResult.status !== 0) {
    console.error('\n❌ Initial knowledge sync failed. Collections may be empty.');
    process.exit(syncResult.status || 1);
  }

  console.log('\n✅ Ready');
  process.exit(0);
}

async function main() {
  const args = process.argv.slice(2);

  if (args[0] === '--version' || args[0] === '-v') {
    const pkgPath = findFileInCliRoot('package.json');
    const pkg = JSON.parse(readFileSync(pkgPath, 'utf8'));
    console.log(`gsd-qdrant-knowledge v${pkg.version}`);
    process.exit(0);
  }

  if (args[0] === 'uninstall') {
    uninstallProjectArtifacts();
    await removeFromGitignore(PROJECT_ROOT, `${TOOL_DIR_NAME}/`);
    console.log('\n✅ Uninstall complete');
    return;
  }

  if (args.length === 0) {
    await bootstrapProject();
    return;
  }

  if (args[0] === 'context') {
    const { GSDKnowledgeSync } = require(findFileInCliRoot('gsd-qdrant-template.js'));
    const intentDetector = require(findFileInCliRoot('intent-detector.js'));
    const query = args[1] || '';
    const project_id = basename(PROJECT_ROOT);

    if (!query) {
      console.log('❌ Please provide a query for context building.');
      console.log('Usage: gsd-qdrant-knowledge context <query>');
      process.exit(1);
    }

    // Detect search intent and build Qdrant filter from certain filters (must)
    // vs uncertain ones (should)
    const intent = intentDetector.detectIntent(query);
    const qdrantFilter = intentDetector.buildQdrantFilter(intent);

    const sync = new GSDKnowledgeSync();
    await sync.init();
    const vector = await sync.embedText(query);

    // Prefetch-based query with group_by: return max 2 chunks per source document.
    // Uses searchPointGroups() to deduplicate across source documents.
    const t0 = Date.now();
    const PREFETCH_LIMIT = 50; // wider prefetch when must-filter applied
    const GROUP_SIZE = 2;        // max chunks per source document
    const LIMIT = 5;             // max results to return
    const SCORE_THRESHOLD = 0.85;  // minimum score for inclusion
    const FALLBACK_THRESHOLD = 0.75; // lowered threshold if too few results

    let hits = [];
    let groupCount = 0;
    try {
      // searchPointGroups requires the vector query directly (no prefetch syntax).
      // We use prefetch inside the query via Qdrant's internal mechanism, but since
      // searchPointGroups does not support prefetch natively, we fall back to the
      // simpler grouped search approach. The must-filter narrows candidates before scoring.
      const groupConfig = {
        vector: { name: sync.vectorName, vector },
        group_by: 'source',
        group_size: GROUP_SIZE,
        limit: LIMIT * 3,  // request more groups so we can filter by threshold after
        score_threshold: SCORE_THRESHOLD,
        with_payload: true,
        with_vector: false,
      };
      if (qdrantFilter) {
        groupConfig.filter = qdrantFilter;
      }
      const groupedResults = await sync.client.searchPointGroups(
        sync.collectionName,
        groupConfig
      );
      groupCount = groupedResults.groups.length;

      // Flatten groups into a single hits array (preserving score order within each group)
      for (const group of groupedResults.groups) {
        hits = hits.concat(group.hits);
      }
    } catch (groupErr) {
      // Fallback: plain search with grouping done client-side if searchPointGroups fails
      console.warn('[qdrant] searchPointGroups not supported, falling back to search');
      try {
        const searchConfig = {
          vector: { name: sync.vectorName, vector },
          limit: LIMIT * 10, // wider search for client-side dedup
          score_threshold: SCORE_THRESHOLD,
          with_payload: true,
          with_vector: false,
        };
        if (qdrantFilter) {
          searchConfig.filter = qdrantFilter;
        }
        const rawHits = await sync.client.search(sync.collectionName, searchConfig);

        // Client-side dedup: max GROUP_SIZE per source document
        const sourceCounts = {};
        for (const hit of rawHits) {
          const src = hit.payload && hit.payload.source;
          if (!src || (sourceCounts[src] || 0) >= GROUP_SIZE) continue;
          sourceCounts[src] = (sourceCounts[src] || 0) + 1;
          hits.push(hit);
        }
        groupCount = Object.keys(sourceCounts).length;
      } catch (searchErr) {
        console.warn('[qdrant] search also failed, returning empty:', searchErr.message);
      }
    }

    // Log totals before threshold filtering
    const totalResults = hits.length;
    console.log('[qdrant] results: %d total, %d above threshold', totalResults, hits.filter(h => h.score >= SCORE_THRESHOLD).length);

    // Apply score threshold filter
    let rankedHits = hits.filter(hit => hit.score >= SCORE_THRESHOLD);

    // Fallback: if fewer than 2 results above threshold, retry with lowered threshold
    if (rankedHits.length < 2 && totalResults > 0) {
      console.log(`[qdrant] fallback: only ${rankedHits.length} results above ${SCORE_THRESHOLD.toFixed(2)}, retrying with ${FALLBACK_THRESHOLD.toFixed(2)}`);
      rankedHits = hits.filter(hit => hit.score >= FALLBACK_THRESHOLD);
    }

    // Map hits to result objects (payload + score), attach _query for path matching
    let rankedResults = rankedHits.map(hit => {
      return { ...hit.payload, score: hit.score, _query: query };
    });

    // Apply recency boost and path matching re-ranking
    applyRecencyBoost(rankedResults);

    // Sort by updated score descending and limit to LIMIT results
    const ranked = rankedResults
      .sort((a, b) => b.score - a.score)
      .slice(0, LIMIT);

    // Token estimation: calculate total tokens across all result text fields
    let totalTokens = 0;
    for (const r of ranked) {
      if (!r) continue;
      const textFields = [r.content, r.summary, r.text].filter(Boolean);
      for (const field of textFields) {
        totalTokens += estimateTokens(field);
      }
    }

    // Trim results if over token budget (4000 tokens default)
    let trimmedInfo;
    try {
      trimmedInfo = trimResultsByTokenBudget(ranked, { maxTokens: 4000 });
    } catch (_) { /* non-fatal — proceed with untrimmed */ }

    const elapsed = Date.now() - t0;
    console.log(`[qdrant] group_by: groups=${groupCount}, chunks=${totalResults} (threshold=${SCORE_THRESHOLD.toFixed(2)} → ${rankedHits.length} above), in ${elapsed}ms`);
    if (trimmedInfo && trimmedInfo.trimmed) {
      const charsPerResult = ranked.filter(r => r._truncated).length;
      console.log(`[retrieval] %d results, ~%d estimated tokens, trimmed to 500 chars per result`, ranked.length, totalTokens);
    }

    // Clean up internal _truncated flag before output
    for (const r of ranked) {
      if (r && '_truncated' in r) delete r._truncated;
    }

    console.log(JSON.stringify({ query, project_id, results: ranked }, null, 2));
    return;
  }

  if (args[0] === 'snippet' && args[1] === 'search') {
    const query = args[2] || '';
    const options = {};

    for (let i = 3; i < args.length; i++) {
      if (args[i].startsWith('--')) {
        const key = args[i].slice(2);
        const value = args[i + 1];
        if (key === 'tags' && value) options.tags = value.split(',');
        if (key === 'language' && value) options.language = value;
        if (key === 'type' && value) options.type = value;
        if (key === 'context') options.withContext = true;
        if (key === 'limit' && value) options.limit = parseInt(value, 10);
      }
    }

    if (!query) {
      console.log('❌ Please provide a search query.');
      console.log('Usage: gsd-qdrant-knowledge snippet search <query> [--tags <tag1,tag2>] [--language <lang>] [--type <type>] [--context] [--limit <n>]');
      process.exit(1);
    }

    const runtimeSyncPath = join(PROJECT_ROOT, TOOL_DIR_NAME, 'index.js');
    const useQdrant = existsSync(runtimeSyncPath);
    let sorted = [];

    if (useQdrant) {
      try {
        const { GSDKnowledgeSync } = require(runtimeSyncPath);
        const sync = new GSDKnowledgeSync();
        await sync.init();
        sorted = await sync.searchWithContext(query, {
          limit: options.limit || 10,
          type: options.type || undefined,
        });
      } catch (err) {
        console.log('⚠️  Qdrant search failed, falling back to local database:', err.message);
      }
    }

    if (sorted.length === 0) {
      const snippetRanking = require(findFileInCliRoot('snippet-ranking'));
      const snippets = snippetRanking.loadDatabase();
      const filtered = snippetRanking.filterAndRankSnippets(snippets, query, options);
      sorted = snippetRanking.sortSnippetsByRelevance(filtered);
    }

    console.log('🔍 Snippet Search');
    console.log('='.repeat(50));
    console.log(`Query: "${query}"`);
    if (options.withContext) console.log('With Context: Yes');
    console.log(`Found ${sorted.length} results:`);

    sorted.forEach((result, i) => {
      console.log(`  ${i + 1}. ${result.path || result.name} (score: ${result.score || result.relevanceScore})`);
      console.log(`     Type: ${result.type}, Scope: ${result.scope}`);
      if (result.milestone || result.slice || result.task) {
        console.log(`     GSD: ${result.milestone || ''} ${result.slice || ''} ${result.task || ''}`.trim());
      }
      console.log(`     ${result.content?.slice(0, 200) || 'No content'}`);
      if (result.context && result.context.length > 0) {
        console.log(`     Context: ${result.context.length} related documents`);
        result.context.forEach(ctx => {
          console.log(`       - ${ctx.source} (${ctx.ids.length} IDs: ${ctx.ids.slice(0, 3).join(', ')})`);
        });
      }
    });

    console.log('='.repeat(50));
    console.log('✅ Search complete!');
    return;
  }

  if (args[0] === 'snippet' && args[1] === 'apply') {
    const query = args[2] || '';

    if (!query) {
      console.log('❌ Please provide a query for the snippet to apply.');
      console.log('Usage: gsd-qdrant-knowledge snippet apply <query>');
      process.exit(1);
    }

    const snippetRanking = require(findFileInCliRoot('snippet-ranking'));
    const intentDetector = require(findFileInCliRoot('intent-detector'));
    const contextAnalyzer = require(findFileInCliRoot('context-analyzer'));
    const intent = intentDetector.detectIntent(query);
    const snippets = snippetRanking.loadDatabase();
    const filtered = snippetRanking.filterAndRankSnippets(snippets, intent.query, {
      tags: intent.filters.tags || [],
      language: (intent.filters.language && !intent.filters.tags?.includes(intent.filters.language)) ? intent.filters.language : '',
      type: intent.filters.type || '',
      crossProject: intent.filters.crossProject || true
    });
    const sorted = snippetRanking.sortSnippetsByRelevance(filtered);

    console.log('📝 Snippet Apply');
    console.log('='.repeat(50));
    console.log(`Query: "${query}"`);

    if (sorted.length === 0) {
      console.log('\n⚠️  No matching snippets found.');
      console.log('='.repeat(50));
      console.log('✅ Search complete (no results)');
      process.exit(0);
    }

    const topMatch = sorted[0];
    const projectContext = contextAnalyzer.analyzeProjectContext();
    const placement = contextAnalyzer.recommendCodePlacement(topMatch.description || query, projectContext);
    const fileExtension = getExtensionForLanguage(topMatch.language);
    const baseFileName = topMatch.sourceFile ? basename(topMatch.sourceFile).replace(extname(topMatch.sourceFile), '') : 'snippet';
    const fileName = `${baseFileName}${fileExtension}`;
    const filePath = join(PROJECT_ROOT, placement.path, fileName);

    let willOverwrite = false;
    if (existsSync(filePath)) {
      const rl = readline.createInterface({ input: process.stdin, output: process.stdout });
      const timeout = setTimeout(() => {
        console.log('\n⚠️  No user input received, defaulting to overwrite.');
        willOverwrite = true;
        rl.close();
      }, 1000);

      await new Promise((resolve) => {
        rl.question('Would you like to overwrite it? (y/N): ', (answer) => {
          clearTimeout(timeout);
          const response = answer.toLowerCase().trim();
          willOverwrite = response === 'y' || response === 'yes';
          rl.close();
          resolve();
        });
      });

      if (!willOverwrite) {
        console.log('❌ File not created (user declined to overwrite).');
        console.log('✅ Operation cancelled.');
        process.exit(0);
      }
    } else {
      const dirPath = dirname(filePath);
      if (!existsSync(dirPath)) mkdirSync(dirPath, { recursive: true });
    }

    writeFileSync(filePath, topMatch.content, 'utf8');
    console.log(`✅ File created successfully: ${filePath}`);
    return;
  }

  await bootstrapProject();
}

